#| echo: true
set.seed(1234)
n <- 10

# generate wind data in polar coordinates
data <- data.frame(
  "x" = rnorm(n), 
  "y" = rnorm(n),
  "dir" = runif(n, -pi, pi), # angle, in radians
  "spd" = rchisq(n, df = 2)  # speed
)

data |> round(digits = 2) |> head()


## ----base-vector-data---------------------------------------------------------
#| echo: true
#| fig.width: 4
#| fig.height: 4
#| fig.align: center
#| warning: false
#| fig.cap: "Plotting (raw) vector data in base R."
#| fig.alt: "A grid of ten 2D arrows in various directions and lengths originating from different locations in the plane."
#| fig.pos: "ht!"
# transform into Cartesian coordinates for plotting
data <- data |> transform( "fx" = spd*cos(dir), "fy" = spd*sin(dir) )

data |> round(digits = 2) |> head()

# plot data
with(data, {
  plot( NULL, xlab = "x", ylab = "y", xlim = range(c(x, x + fx)), ylim = range(c(y, y + fy)) )
  arrows(x, y, x + fx, y + fy, length = .10)
})


## ----base-vector-field--------------------------------------------------------
#| echo: true
#| fig.width: 4
#| fig.height: 4
#| fig.align: center
#| warning: false
#| fig.cap: "Vector fields can be visualized by sampling their domain, evaluating the vector field, and plotting the resulting vectors as translated arrows. Here the rotational field $\\mathbf{f}(x,y) = (-y,x)$ is visualized using base R graphics using the same strategy as Figure~\\ref{fig:base-vector-data}."
#| fig.alt: "Uniform grid of small arrows showing rotation around the origin; arrows point tangentially to concentric circles."
#| fig.pos: "ht!"
# define vector field of single vector argument
f <- function(u) {
  x <- u[1]; y <- u[2]
  c(-y, x)
}

# make data frame grid with space for (fx(x,y), fy(x,y))
N <- 11
df <- expand.grid( "x" = seq(-1, 1, len = N), "y" = seq(-1, 1, len = N) )
df$fy <- df$fx <- NA # make placeholders for fx(x,y) and fy(x,y) values

# evaluate f(u) at each point and look at result
for (i in 1:nrow(df)) df[i,3:4] <- f( as.numeric(df[i,1:2]) )

head(df)

# visualize using base R
with(na.omit(df), { 
  plot( NULL, xlab = "x", ylab = "y", xlim = range(x, x + fx), ylim = range(y, y + fy) )
  arrows(x, y, x + fx, y + fy, length = .05)
})


